ce:nowrap}.wastage-actions{display:inline-flex;gap:5px;min-width:150px;justify-content:flex-end}.wastage-actions .icon-btn{width:30px;height:30px;border-radius:6px;background:color-mix(in srgb,currentColor 10%,var(--surface));border-color:color-mix(in srgb,currentColor 26%,var(--border))}.action-view{color:#2563eb}.action-edit{color:#f97316}.action-post{color:#16a34a}.action-cancel,.action-delete{color:#dc2626}.wastage-modal-body{display:grid;gap:14px;padding-bottom:70px}.wastage-form-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:12px}.wastage-audit-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px}.wastage-audit-fact{padding:10px;border:1px solid var(--border);border-radius:8px;background:var(--surface-soft)}.wastage-audit-fact span{display:block;color:var(--muted);font-size:11px;font-weight:900;text-transform:uppercase}.wastage-audit-fact strong{display:block;margin-top:4px;font-size:13px;word-break:break-word}@media(max-width:900px){.wastage-card-head,.wastage-filter-row,.wastage-table-toolbar,.pagination-row{align-items:stretch;flex-direction:column}.wastage-filter-group,.pager-actions,.module-actions{width:100%;flex-wrap:wrap}.wastage-filter-group select,.wastage-filter-group input,.wastage-filter-group .btn-erp,.pager-actions .btn-erp,.module-actions .btn-erp{width:100%}.wastage-data-table-wrap{max-height:none;min-height:0;margin-inline:12px}.wastage-form-grid,.wastage-audit-grid{grid-template-columns:1fr}}
