<script>
const endpoint='/v1/wastage',authUser=JSON.parse(localStorage.getItem('user')||'{}'),permissions=authUser.permissions||[],isSuperAdmin=authUser.role_name==='Super Admin';
const canManage=permissions.includes('wastage.manage')||isSuperAdmin,canPost=permissions.includes('wastage.post')||isSuperAdmin,canCancel=permissions.includes('wastage.cancel')||isSuperAdmin;
const columnOptions=[['date','Date'],['item','Item'],['location','Location'],['type','Type'],['source','Source'],['generated','Generated'],['available','Available'],['used','Used'],['status','Status']],defaultVisibleColumns=columnOptions.map(x=>x[0]),columnStorageKey='wastage.visibleColumns';
let page=1,last=1,timer,records=[],items=[],locations=[],activeMode='create',activeId=null,visibleColumns=readVisibleColumns(),processing=false,paginationMeta={from:0,to:0,total:0},sortBy=sessionStorage.getItem('wastage.sortBy')||'transaction_date',sortDirection=sessionStorage.getItem('wastage.sortDirection')||'desc';
const esc=v=>(v??'').toString().replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m])),num=v=>Number(v||0).toLocaleString(undefined,{maximumFractionDigits:3}),opt=(rows,k,l,p)=>`<option value="">${p}</option>`+rows.map(r=>`<option value="${r[k]}">${esc(r[l]||r[k])}</option>`).join('');
function readVisibleColumns(){try{const s=JSON.parse(localStorage.getItem(columnStorageKey)||'null');if(Array.isArray(s)&&s.length)return s}catch{}return defaultVisibleColumns}
async function lookup(e){return window.ErpApi?.cachedList ? window.ErpApi.cachedList(e) : (await axios.get(e,{params:{per_page:100}})).data.data.data||[]}
async function boot(){document.querySelectorAll('[data-manage-only]').forEach(el=>el.hidden=!canManage);[items,locations]=await Promise.all([lookup('/v1/items'),lookup('/v1/locations')]);filterItem.innerHTML=opt(items,'item_id','item_name','All Items');filterLocation.innerHTML=opt(locations,'location_id','location_name','All Locations');colItem.innerHTML=opt(items,'item_id','item_name','All');colLocation.innerHTML=opt(locations,'location_id','location_name','All');renderColumnPicker();restoreState();load()}
function storeSort(){sessionStorage.setItem('wastage.sortBy',sortBy);sessionStorage.setItem('wastage.sortDirection',sortDirection)}
function params(){storeSort();return{page,per_page:perPage.value,search:search.value,status:colStatus.value||filterStatus.value,date_from:colDate.value||filterDateFrom.value,date_to:filterDateTo.value,item_id:colItem.value||filterItem.value,location_id:colLocation.value||filterLocation.value,source_module:colSource.value||filterSource.value,sort_by:sortBy,sort_direction:sortDirection}}
function clientFiltered(data){return data.filter(x=>(!colType.value||x.wastage_type===colType.value)&&(!colGeneratedMin.value||Number(x.generated_qty||0)>=Number(colGeneratedMin.value))&&(!colAvailableMin.value||Number(x.available_qty||0)>=Number(colAvailableMin.value))&&(!colUsedMin.value||Number(x.used_qty||0)>=Number(colUsedMin.value)))}
async function load(p=page){page=p;storeState();rows.innerHTML='<tr class="skeleton-row"><td colspan="10"></td></tr>';const r=await axios.get(endpoint,{params:params()});const d=r.data.data;page=d.current_page;last=d.last_page;paginationMeta={from:d.from||0,to:d.to||0,total:d.total||0};records=clientFiltered(d.data||[]);renderRows();renderSortHeaders();renderPager()}
function badge(s){const c=s==='Posted'?'badge-success':s==='Cancelled'?'badge-danger':'badge-warning';return`<span class="badge ${c}">${esc(s)}</span>`}
function renderRows(){rows.innerHTML=records.length?records.map(x=>`<tr><td data-col="date">${esc(x.transaction_date)}</td><td data-col="item"><strong>${esc(x.item_name)}</strong></td><td data-col="location">${esc(x.location_name)}</td><td data-col="type">${esc(x.wastage_type)}</td><td data-col="source">${esc(x.source_reference||x.source_module)}</td><td data-col="generated" class="text-end">${num(x.generated_qty)}</td><td data-col="available" class="text-end">${num(x.available_qty)}</td><td data-col="used" class="text-end">${num(x.used_qty)}</td><td data-col="status">${badge(x.status)}</td><td class="text-end action-col"><span class="wastage-actions"><button class="icon-btn action-view" data-view="${x.wastage_stock_id}" title="View"><i data-lucide="eye"></i></button>${canManage&&x.status==='Draft'&&x.source_module==='Manual'?`<button class="icon-btn action-edit" data-edit="${x.wastage_stock_id}" title="Edit"><i data-lucide="pencil"></i></button><button class="icon-btn action-delete" data-delete="${x.wastage_stock_id}" title="Delete"><i data-lucide="trash-2"></i></button>`:''}${canPost&&x.status==='Draft'?`<button class="icon-btn action-post" data-post="${x.wastage_stock_id}" title="Post"><i data-lucide="check-circle"></i></button>`:''}${canCancel&&x.status==='Posted'&&Number(x.used_qty||0)===0?`<button class="icon-btn action-cancel" data-cancel="${x.wastage_stock_id}" title="Cancel"><i data-lucide="ban"></i></button>`:''}</span></td></tr>`).join(''):'<tr><td colspan="10" class="text-muted">No wastage records found.</td></tr>';applyColumnVisibility();lucide?.createIcons()}
function renderSortHeaders(){document.querySelectorAll('[data-sort]').forEach(button=>{const active=button.dataset.sort===sortBy;button.classList.toggle('is-active',active);const label=button.dataset.label||button.textContent.trim();button.dataset.label=label;button.innerHTML=`${label} <i data-lucide="${active?(sortDirection==='asc'?'arrow-up':'arrow-down'):'chevrons-up-down'}"></i>`});lucide?.createIcons()}
function pageRange(){const pages=[];if(last<=7){for(let i=1;i<=last;i++)pages.push(i);return pages}pages.push(1);let start=Math.max(2,page-1),end=Math.min(last-1,page+1);if(page<=2){start=2;end=3}else if(page>=last-1){start=last-2;end=last-1}if(start>2)pages.push('...');for(let i=start;i<=end;i++)pages.push(i);if(end<last-1)pages.push('...');pages.push(last);return pages}
function renderPager(){pageLinks.innerHTML=pageRange().map(v=>v==='...'?'<span class="page-number-ellipsis">...</span>':`<button class="btn-erp btn-page-number ${Number(v)===page?'is-active':''}" type="button" data-page="${v}">${v}</button>`).join('');pageStatus.textContent=paginationMeta.total?`Showing ${paginationMeta.from} to ${paginationMeta.to} of ${paginationMeta.total} records`:'Showing 0 to 0 of 0 records';document.querySelector('[data-action="prev-page"]').disabled=page<=1;document.querySelector('[data-action="next-page"]').disabled=page>=last;lucide?.createIcons()}
function renderColumnPicker(){columnPickerMenu.innerHTML=columnOptions.map(([k,l])=>`<label><input type="checkbox" value="${k}" ${visibleColumns.includes(k)?'checked':''}><span>${l}</span></label>`).join('')}
function applyColumnVisibility(){const visible=new Set(visibleColumns);document.querySelectorAll('.wastage-data-table [data-col]').forEach(c=>c.classList.toggle('is-hidden-column',!visible.has(c.dataset.col)))}
function updateColumnVisibility(c,on){visibleColumns=on?[...new Set([...visibleColumns,c])]:visibleColumns.filter(x=>x!==c);localStorage.setItem(columnStorageKey,JSON.stringify(visibleColumns));applyColumnVisibility()}
function toggleFilterRow(){const row=document.getElementById('wastage-filter-row'),head=document.getElementById('wastage-filter-head'),button=document.querySelector('[data-action="toggle-filter-row"]'),open=row.hidden;row.hidden=!open;if(head)head.hidden=!open;button.classList.toggle('is-active',open);button.setAttribute('aria-pressed',open?'true':'false');button.title=open?'Hide filters':'Show filters'}
function storeState(){['search','filterStatus','filterDateFrom','filterDateTo','filterItem','filterLocation','filterSource','perPage'].forEach(k=>sessionStorage.setItem(`wastage.${k}`,window[k].value))}
function restoreState(){search.value=sessionStorage.getItem('wastage.search')||'';filterStatus.value=sessionStorage.getItem('wastage.filterStatus')||'';filterDateFrom.value=sessionStorage.getItem('wastage.filterDateFrom')||'';filterDateTo.value=sessionStorage.getItem('wastage.filterDateTo')||'';filterItem.value=sessionStorage.getItem('wastage.filterItem')||'';filterLocation.value=sessionStorage.getItem('wastage.filterLocation')||'';filterSource.value=sessionStorage.getItem('wastage.filterSource')||'';perPage.value=sessionStorage.getItem('wastage.perPage')||'10'}
function resetFilters(){[search,filterStatus,filterDateFrom,filterDateTo,filterItem,filterLocation,filterSource,colDate,colItem,colLocation,colType,colSource,colGeneratedMin,colAvailableMin,colUsedMin,colStatus].forEach(el=>el.value='');perPage.value='10';sortBy='transaction_date';sortDirection='desc';load(1)}
function auditFact(l,v){return`<div class="wastage-audit-fact"><span>${l}</span><strong>${esc(v||'-')}</strong></div>`}
function modalBody(readonly=false){return`<div class="wastage-modal-body"><div class="wastage-form-grid"><div class="field"><i data-lucide="calendar"></i><label>Date *</label><input id="modal-date" type="date" ${readonly?'disabled':''}></div><div class="field"><i data-lucide="package"></i><label>Item *</label><select id="modal-item" ${readonly?'disabled':''}>${opt(items,'item_id','item_name','Item')}</select></div><div class="field"><i data-lucide="map-pin"></i><label>Location *</label><select id="modal-location" ${readonly?'disabled':''}>${opt(locations,'location_id','location_name','Location')}</select></div><div class="field"><i data-lucide="recycle"></i><label>Type *</label><select id="modal-type" ${readonly?'disabled':''}><option>Reusable</option><option>Non-Reusable</option><option>Scrap</option></select></div><div class="field"><i data-lucide="scale"></i><label>Qty *</label><input id="modal-qty" type="number" step="0.001" min="0.001" ${readonly?'disabled':''}></div><div class="field"><i data-lucide="hash"></i><label>Reference</label><input id="modal-reference" ${readonly?'disabled':''}></div><div class="field" style="grid-column:1/-1"><i data-lucide="message-square"></i><label>Remarks</label><input id="modal-remarks" ${readonly?'disabled':''}></div></div><div id="modal-audit"></div><div id="modal-errors" class="form-errors" hidden></div></div>`}
function modalEl(id){return document.getElementById(id)}
async function openModal(mode,id=null){activeMode=mode;activeId=id;const readonly=mode==='view';window.ErpModal.open({title:mode==='create'?'Add Wastage Adjustment':mode==='edit'?'Edit Wastage':'Display Wastage',subtitle:'Manual adjustments are posted through stock ledger entries.',size:'lg',body:modalBody(readonly),footer:readonly?'<button class="btn-erp" data-modal-close><i data-lucide="x"></i> Close</button>':'<button class="btn-erp" data-modal-close><i data-lucide="x"></i> Cancel</button><button class="btn-erp btn-primary" data-action="save"><i data-lucide="save"></i> Save Draft</button>'});if(mode==='create'){modalEl('modal-date').value=new Date().toISOString().slice(0,10);modalEl('modal-qty').value=1;return}const r=await axios.get(`${endpoint}/${id}`),x=r.data.data;modalEl('modal-date').value=x.transaction_date||'';modalEl('modal-item').value=x.item_id||'';modalEl('modal-location').value=x.location_id||'';modalEl('modal-type').value=x.wastage_type||'Reusable';modalEl('modal-qty').value=x.generated_qty||0;modalEl('modal-reference').value=x.source_reference||'';modalEl('modal-remarks').value=x.remarks||'';modalEl('modal-audit').innerHTML=`<div class="wastage-audit-grid">${auditFact('Source',x.source_module)}${auditFact('Available',num(x.available_qty))}${auditFact('Posted At',x.posted_at)}${auditFact('Cancelled At',x.cancelled_at)}</div>`}
function payload(){return{transaction_date:modalEl('modal-date').value,item_id:modalEl('modal-item').value,location_id:modalEl('modal-location').value,wastage_type:modalEl('modal-type').value,generated_qty:modalEl('modal-qty').value,source_reference:modalEl('modal-reference').value,remarks:modalEl('modal-remarks').value}}
async function save(){const box=modalEl('modal-errors');box.hidden=true;try{if(activeMode==='edit')await axios.put(`${endpoint}/${activeId}`,payload());else await axios.post(endpoint,payload());window.ErpApi?.clearLookupCache?.();window.ErpModal.close();await load(page);window.ErpToast?.show('Wastage saved.')}catch(e){box.textContent=e.normalizedMessage||'Unable to save wastage.';box.hidden=false}}
function confirmAction(id,type){const isCancel=type==='cancel';window.ErpModal.open({title:isCancel?'Cancel Wastage':'Post Wastage',subtitle:isCancel?'Cancellation reverses stock when not reused.':'Posting creates wastage stock movement.',size:isCancel?'md':'sm',body:isCancel?'<div class="field"><i data-lucide="message-square"></i><label>Reason</label><input id="action-reason"></div><div id="action-errors" class="form-errors" hidden></div>':'<p>Post this wastage adjustment?</p><div id="action-errors" class="form-errors" hidden></div>',footer:`<button class="btn-erp" data-modal-close><i data-lucide="x"></i> Close</button><button class="btn-erp ${isCancel?'btn-danger':'btn-primary'}" data-confirm-${type}="${id}"><i data-lucide="${isCancel?'ban':'check-circle'}"></i> ${isCancel?'Cancel Wastage':'Post'}</button>`})}
async function doAction(button,type){if(processing)return;processing=true;button.disabled=true;try{const id=button.dataset[`confirm${type[0].toUpperCase()+type.slice(1)}`];await axios.post(`${endpoint}/${id}/${type}`,{reason:document.getElementById('action-reason')?.value||''});window.ErpModal.close();await load(page);window.ErpToast?.show(type==='post'?'Wastage posted.':'Wastage cancelled.')}catch(e){const box=document.getElementById('action-errors');if(box){box.textContent=e.normalizedMessage||'Action failed.';box.hidden=false}else window.ErpToast?.show(e.normalizedMessage||'Action failed.','danger')}finally{processing=false}}
function csvExport(){const active=columnOptions.filter(([k])=>visibleColumns.includes(k)),map={date:x=>x.transaction_date,item:x=>x.item_name,location:x=>x.location_name,type:x=>x.wastage_type,source:x=>x.source_reference||x.source_module,generated:x=>x.generated_qty,available:x=>x.available_qty,used:x=>x.used_qty,status:x=>x.status};const csv=[active.map(([,l])=>`"${l}"`).join(','),...records.map(r=>active.map(([k])=>`"${String(map[k](r)??'').replaceAll('"','""')}"`).join(','))].join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv'}));a.download='wastage-adjustment.csv';a.click();URL.revokeObjectURL(a.href)}
document.addEventListener('DOMContentLoaded',()=>{window.perPage=per_page;window.filterDateFrom=document.getElementById('filter-date-from');window.filterDateTo=document.getElementById('filter-date-to');window.filterItem=document.getElementById('filter-item');window.filterLocation=document.getElementById('filter-location');window.filterSource=document.getElementById('filter-source');window.filterStatus=document.getElementById('filter-status');window.colDate=document.getElementById('col-date');window.colItem=document.getElementById('col-item');window.colLocation=document.getElementById('col-location');window.colType=document.getElementById('col-type');window.colSource=document.getElementById('col-source');window.colGeneratedMin=document.getElementById('col-generated-min');window.colAvailableMin=document.getElementById('col-available-min');window.colUsedMin=document.getElementById('col-used-min');window.colStatus=document.getElementById('col-status');window.pageStatus=document.getElementById('page-status');window.pageLinks=document.getElementById('page-links');window.columnPickerMenu=document.getElementById('column-picker-menu');boot();document.querySelector('[data-action="new"]').onclick=()=>openModal('create');document.querySelector('[data-action="reload"]').onclick=()=>load(page);document.querySelector('[data-action="apply"]').onclick=()=>load(1);document.querySelector('[data-action="reset"]').onclick=resetFilters;document.querySelector('[data-action="toggle-filter-row"]').onclick=toggleFilterRow;document.querySelector('[data-action="clear-search"]').onclick=()=>{search.value='';load(1)};document.querySelector('[data-action="prev-page"]').onclick=()=>page>1&&load(page-1);document.querySelector('[data-action="next-page"]').onclick=()=>page<last&&load(page+1);pageLinks.addEventListener('click',e=>{const target=e.target.closest('[data-page]');if(target)load(Number(target.dataset.page))});document.querySelector('[data-action="export"]').onclick=csvExport;document.querySelector('[data-action="print"]').onclick=()=>window.print();document.querySelector('[data-action="toggle-columns"]').onclick=function(){const p=this.closest('.column-picker');p.classList.toggle('is-open');this.setAttribute('aria-expanded',p.classList.contains('is-open')?'true':'false')};columnPickerMenu.addEventListener('change',e=>{const cb=e.target.closest('input[type="checkbox"]');if(cb)updateColumnVisibility(cb.value,cb.checked)});document.querySelectorAll('[data-sort]').forEach(button=>button.addEventListener('click',function(){if(sortBy===this.dataset.sort)sortDirection=sortDirection==='asc'?'desc':'asc';else{sortBy=this.dataset.sort;sortDirection='asc'}load(1)}));[perPage,filterStatus,filterDateFrom,filterDateTo,filterItem,filterLocation,filterSource,colDate,colItem,colLocation,colType,colSource,colStatus].forEach(el=>el.addEventListener('change',()=>load(1)));[search,colGeneratedMin,colAvailableMin,colUsedMin].forEach(el=>el.addEventListener('input',()=>{clearTimeout(timer);timer=setTimeout(()=>load(1),300)}));rows.addEventListener('click',async e=>{const v=e.target.closest('[data-view]')?.dataset.view,ed=e.target.closest('[data-edit]')?.dataset.edit,p=e.target.closest('[data-post]')?.dataset.post,c=e.target.closest('[data-cancel]')?.dataset.cancel,d=e.target.closest('[data-delete]')?.dataset.delete;if(v)await openModal('view',v);if(ed)await openModal('edit',ed);if(p)confirmAction(p,'post');if(c)confirmAction(c,'cancel');if(d)window.ErpModal.open({title:'Delete Wastage',subtitle:'Only draft manual wastage can be deleted.',size:'sm',body:'<p>Delete this wastage draft?</p>',footer:`<button class="btn-erp" data-modal-close><i data-lucide="x"></i> Cancel</button><button class="btn-erp btn-danger" data-confirm-delete="${d}"><i data-lucide="trash-2"></i> Delete</button>`})});document.addEventListener('click',async e=>{if(!e.target.closest('.column-picker'))document.querySelector('.column-picker')?.classList.remove('is-open');if(e.target.closest('[data-action="save"]'))await save();const p=e.target.closest('[data-confirm-post]');if(p)await doAction(p,'post');const c=e.target.closest('[data-confirm-cancel]');if(c)await doAction(c,'cancel');const d=e.target.closest('[data-confirm-delete]')?.dataset.confirmDelete;if(d){try{await axios.delete(`${endpoint}/${d}`);window.ErpModal.close();await load(page);window.ErpToast?.show('Wastage deleted.')}catch(e){window.ErpToast?.show(e.normalizedMessage||'Delete failed.','danger')}}})});
</script>
@endpush
